mapper.select:
SELECT 
FROM clarification_request
WHERE status = 'OPEN'
  AND (
      (#{jobId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
           IS NULL AND job_id IS NULL)
      OR job_id =
         #{jobId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
  )
  AND (
      (#{taskId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
           IS NULL AND task_id IS NULL)
      OR task_id =
         #{taskId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
  )
  AND (
      (#{taskRunId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
           IS NULL AND task_run_id IS NULL)
      OR task_run_id =
         #{taskRunId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
  )
  AND (
      (#{loopNodeId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
           IS NULL AND loop_node_id IS NULL)
      OR loop_node_id =
         #{loopNodeId,typeHandler=com.funjson.metaagent.common.persistence.mybatis.UuidBinaryTypeHandler,jdbcType=BINARY}
  )
ORDER BY created_at
